// Регистрация контракта для запроса разрешений
private val requestPermissionLauncher = registerForActivityResult(
    ActivityResultContracts.RequestPermission()
) { isGranted: Boolean ->
    if (isGranted) {
        // Разрешение получено
        startCamera()
    } else {
        // Разрешение отклонено
        showPermissionDeniedDialog()
    }
}

// Для нескольких разрешений
private val requestMultiplePermissionsLauncher = registerForActivityResult(
    ActivityResultContracts.RequestMultiplePermissions()
) { permissions: Map<String, Boolean> ->
    permissions.forEach { (permission, isGranted) ->
        when {
            isGranted -> {
                // Каждое разрешение обрабатываем отдельно
                handlePermissionGranted(permission)
            }
            shouldShowRequestPermissionRationale(permission) -> {
                showRationaleForPermission(permission)
            }
            else -> {
                openAppSettingsForPermission()
            }
        }
    }
}

// Использование
fun checkAndRequestCameraPermission() {
    when {
        ContextCompat.checkSelfPermission(
            this, 
            Manifest.permission.CAMERA
        ) == PackageManager.PERMISSION_GRANTED -> {
            startCamera()
        }
        shouldShowRequestPermissionRationale(Manifest.permission.CAMERA) -> {
            // Показываем объяснение перед запросом
            showCameraPermissionRationale()
        }
        else -> {
            // Запрашиваем разрешение
            requestPermissionLauncher.launch(Manifest.permission.CAMERA)
        }
    }
}

class PermissionViewModel : ViewModel() {
    private val _permissionState = MutableStateFlow<PermissionState>(PermissionState.Idle)
    val permissionState: StateFlow<PermissionState> = _permissionState

    sealed class PermissionState {
        object Idle : PermissionState()
        object Checking : PermissionState()
        data class Granted(val permission: String) : PermissionState()
        data class Denied(val permission: String, val showRationale: Boolean) : PermissionState()
    }

    fun checkPermission(context: Context, permission: String) {
        viewModelScope.launch {
            _permissionState.value = PermissionState.Checking

            val isGranted = ContextCompat.checkSelfPermission(
                context, 
                permission
            ) == PackageManager.PERMISSION_GRANTED

            _permissionState.value = if (isGranted) {
                PermissionState.Granted(permission)
            } else {
                PermissionState.Denied(
                    permission = permission,
                    showRationale = ActivityCompat.shouldShowRequestPermissionRationale(
                        context as Activity, 
                        permission
                    )
                )
            }
        }
    }
}
